class AstroidTransform{scenes=[];scrollConfig={};timelineConfig={};el=null;constructor(el){this.el=el.dataset.transformTrigger?el.querySelectorAll(el.dataset.transformTrigger):el;this.scenes=JSON.parse(el.dataset.transformScenes);this.scrollConfig=el.dataset.transformScroll?JSON.parse(el.dataset.transformScroll):{};this.timelineConfig=el.dataset.transformTimeline?JSON.parse(el.dataset.transformTimeline):{};this.timelineConfig.paused=true;if(this.timelineConfig.repeat){this.timelineConfig.repeat=this.timelineConfig.repeat==="true"?-1:parseInt(this.timelineConfig.repeat)}if(this.scrollConfig.scrub){this.scrollConfig.scrub=this.scrollConfig.scrub==="true"?true:parseFloat(this.scrollConfig.scrub)}}init(){const tl=gsap.timeline(this.timelineConfig);this.scenes.forEach(scene=>{if(scene.from&&scene.to){tl.fromTo(this.el,scene.from,scene.to)}else if(scene.from){tl.from(this.el,scene.from)}else{tl.to(this.el,scene.to||{})}});ScrollTrigger.create({...{trigger:this.el,animation:tl},...this.scrollConfig})}}document.addEventListener("DOMContentLoaded",()=>{gsap.registerPlugin(ScrollTrigger);document.querySelectorAll("[data-transform-scenes]").forEach(el=>{const transform=new AstroidTransform(el);transform.init()})});